INSERT INTO transfer_outgoing VALUES(1,'2026-summer',3,'Arsenal','MEDIUM','아르테타 주도, 아스널이 콘사에 관심. 빌라는 £60m 밸류에이션 — 아스널은 고평가로 판단, 아직 오퍼 없음.','https://www.telegraph.co.uk (Arsenal Ezri Konsa interest, 2026-07-03)','HIGH — Telegraph(2티어) 단독 관심 보도. 협상/합의 단계 아님.');
INSERT INTO transfer_outgoing VALUES(2,'2026-summer',13,'Arsenal','MEDIUM','아스널이 넘버원 타겟으로 로저스 추진, 로저스 본인도 아스널·바이에른 외 이적 의사 없음이라 보도. 개인조건 합의설은 3티어 다수 보도(football365/teamtalk/goal.com)뿐 — 미확정. 빌라 £100m+ 요구, 협상 초기.','https://www.football365.com (다수), https://www.teamtalk.com, https://www.goal.com; Telegraph(2티어)는 "오랜 관심"만 언급','MEDIUM — 관심·희망 단계는 Telegraph 언급으로 뒷받침되나, "개인조건 합의" 구체 주장은 3티어 전용이라 미확인으로 표기.');
